import{_ as t,c as r,o as n,a5 as i,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.36: Enable Thinking Mode, Multiple UI Improvements","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.36.md","filePath":"en/changelog/v1.1.36.md","lastUpdated":1772014034000}'),o={name:"en/changelog/v1.1.36.md"};function l(s,a,h,d,u,p){return n(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="v1-1-36-enable-thinking-mode-multiple-ui-improvements" tabindex="-1">v1.1.36: Enable Thinking Mode, Multiple UI Improvements <a class="header-anchor" href="#v1-1-36-enable-thinking-mode-multiple-ui-improvements" aria-label="Permalink to “v1.1.36: Enable Thinking Mode, Multiple UI Improvements”">​</a></h1><p><strong>Release Date</strong>: January 25, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update enables Thinking mode for Google Vertex Anthropic models and improves multiple TUI and Desktop details.</p><hr><h2 id="new-feature-thinking-mode-support" tabindex="-1">New Feature: Thinking Mode Support <a class="header-anchor" href="#new-feature-thinking-mode-support" aria-label="Permalink to “New Feature: Thinking Mode Support”">​</a></h2><h3 id="what-was-updated" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated" aria-label="Permalink to “What was updated?”">​</a></h3><p>Now when using Anthropic models on Google Vertex AI, you can use Thinking mode to have the model show its thinking process.</p><h3 id="what-is-thinking-mode" tabindex="-1">What is Thinking Mode? <a class="header-anchor" href="#what-is-thinking-mode" aria-label="Permalink to “What is Thinking Mode?”">​</a></h3><p>Thinking mode allows AI models to display their thinking process before generating final answers, which is very helpful for understanding and debugging complex problems.</p><h3 id="how-to-use" tabindex="-1">How to use? <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to use?”">​</a></h3><ol><li>Make sure you&#39;re using Google Vertex AI&#39;s Anthropic model</li><li>Include the thinking parameter in your request</li><li>The model will first show its thinking process, then give the final answer</li></ol><hr><h2 id="bug-fix-theme-search-crash" tabindex="-1">Bug Fix: Theme Search Crash <a class="header-anchor" href="#bug-fix-theme-search-crash" aria-label="Permalink to “Bug Fix: Theme Search Crash”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>Searching for themes in TUI would crash if there were no matching results.</p><h3 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to “Current Status”">​</a></h3><p>Thanks to community contributor @ishaksebsib&#39;s fix, now when search returns no results, a normal prompt is displayed instead of crashing.</p><hr><h2 id="bug-fix-download-button" tabindex="-1">Bug Fix: Download Button <a class="header-anchor" href="#bug-fix-download-button" aria-label="Permalink to “Bug Fix: Download Button”">​</a></h2><h3 id="previous-issue-1" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-1" aria-label="Permalink to “Previous Issue”">​</a></h3><p>The download button in the Web interface was missing or not working properly.</p><h3 id="current-status-1" tabindex="-1">Current Status <a class="header-anchor" href="#current-status-1" aria-label="Permalink to “Current Status”">​</a></h3><p>Fixed and improved the download button functionality.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Using Google Vertex Anthropic</td><td>✅ Highly recommended</td></tr><tr><td>Using TUI</td><td>✅ Recommended upgrade (crash fix)</td></tr><tr><td>Everything working fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade command</strong>:</p>',29),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),i('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Enable thinking for Google Vertex Anthropic models (@MichaelYochpaz)</li><li>Make question validation more lax to avoid tool call failures</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Prevent crash when theme search returns no results (@ishaksebsib)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Visual cleanup in app</li><li>Scroll to comment on click in app</li><li>Fixed crash when no default model is set</li><li>Performance improvements in the app package</li><li>Clean up comment component usage in app</li></ul><p><strong>Thank you to 5 community contributors:</strong></p><p>@MichaelYochpaz:</p><ul><li>fix(provider): enable thinking for google-vertex-anthropic models (#10442)</li></ul><p>@ProdigyRahul:</p><ul><li>fix(app): cursor on resize (#10293)</li></ul><p>@DNGriffin:</p><ul><li>fix(app): mobile horizontal scrolling due to session stat btn (#10487)</li></ul><p>@ishaksebsib:</p><ul><li>fix(tui): prevent crash when theme search returns no results (#10565)</li></ul><p>@R44VC0RP:</p><ul><li>fix(web): add &amp; fix the download button (#10566)</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const g=t(o,[["render",l]]);export{m as __pageData,g as default};
